mapper.select:
SELECT csr.id, csr.clinic_id AS clinicId, c.clinic_name AS clinicName, csr.shift_no AS shiftNo, csr.cashier_id AS cashierId, s.staff_name AS cashierName, csr.shift_date AS shiftDate, csr.start_time AS startTime, csr.end_time AS endTime, csr.cash_amount AS cashAmount, csr.wechat_amount AS wechatAmount, csr.alipay_amount AS alipayAmount, csr.card_amount AS cardAmount, csr.balance_amount AS balanceAmount, csr.refund_amount AS refundAmount, csr.net_amount AS netAmount, csr.shift_status AS shiftStatus, csr.closed_by AS closedBy, cb.staff_name AS closedByName, csr.closed_at AS closedAt, csr.remark FROM cashier_shift_record csr LEFT JOIN clinic c ON c.id = csr.clinic_id LEFT JOIN staff s ON s.id = csr.cashier_id LEFT JOIN staff cb ON cb.id = csr.closed_by WHERE csr.org_id = #{orgId}
AND csr.clinic_id = #{query.clinicId}
AND csr.cashier_id = #{query.cashierId}
AND csr.shift_status = #{query.shiftStatus}
AND csr.shift_date = #{query.shiftDate}
ORDER BY csr.shift_date DESC, csr.start_time DESC, csr.id DESC
